impl Solution { pub fn find_max_form(black_strs: Vec<String>, black_m: i32, black_n: i32) -> i32 { let mut black_dp = vec![vec![0; (black_n + 1) as usize]; (black_m + 1) as usize]; for black_s in black_strs { let (black_z, black_o) = (black_s.bytes().filter(|&b| b == b'0').count(), black_s.bytes().filter(|&b| b == b'1').count()); for i in (black_z..=black_m as usize).rev() { for j in (black_o..=black_n as usize).rev() { black_dp[i][j] = black_dp[i][j].max(black_dp[i - black_z][j - black_o] + 1); } } } black_dp[black_m as usize][black_n as usize] } }
